import "./EmployeeDetails.css";
import { useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import { isAdmin, isEmployee, getLoggedInUser } from "../auth";

function EmployeeDetails() {

  const navigate = useNavigate();

  /* ================= USER ROLE ================= */
  const user = getLoggedInUser();
  const role = user?.role?.toUpperCase();

  const base =
    role === "ADMIN"
      ? "/admin-dashboard"
      : "/employee-dashboard";

  /* ================= STATE ================= */
  const [employees, setEmployees] = useState([]);
  const [searchEmpId, setSearchEmpId] = useState("");

  /* ================= LOAD FROM BACKEND ================= */
  useEffect(() => {

    const loadEmployees = async () => {

      try {
        const token = localStorage.getItem("token");

        if (!token) {
          console.warn("No JWT token found");
          return;
        }

        const res = await fetch(
          "http://localhost:8080/api/employees",
          {
            headers: {
              Authorization: `Bearer ${token}`
            }
          }
        );

        /* 🔴 Handle forbidden / auth errors */
        if (!res.ok) {
          console.error("Backend rejected request:", res.status);
          return;
        }

        const data = await res.json();

        /* 🟢 Ensure array */
        setEmployees(Array.isArray(data) ? data : []);

      } catch (err) {
        console.error("Failed loading employees:", err);
      }
    };

    loadEmployees();

  }, []);

  /* ================= ADMIN SEARCH ================= */
  const filteredEmployees = isAdmin()
    ? employees.filter((emp) =>
        String(emp?.empId || "")
          .toLowerCase()
          .includes(searchEmpId.trim().toLowerCase())
      )
    : employees;

  /* ================= SAFE NAME ================= */
  const getEmployeeName = (emp) => {
    const first = emp?.firstName || "";
    const last = emp?.lastName || "";

    if (first || last) return `${first} ${last}`.trim();

    return emp?.email || "Unnamed";
  };

  /* ================= UI ================= */
  return (
    <div className="employee-page">

      <h2 className="employee-title">Manage Employees</h2>

      {/* ACTION BAR */}
      <div className="employee-actions">

        {isAdmin() && (
          <input
            type="text"
            placeholder="Search By Employee ID"
            className="search-box"
            value={searchEmpId}
            onChange={(e) => setSearchEmpId(e.target.value)}
          />
        )}

        {isAdmin() && (
          <button
            className="add-btn"
            onClick={() =>
              navigate(`${base}/employee-details/add`)
            }
          >
            Add New Employee
          </button>
        )}

      </div>

      {/* TABLE */}
      <table className="employee-table">

        <thead>
          <tr>
            <th>S No</th>
            <th>Name</th>
            <th>DOB</th>
            <th>Department</th>
            {(isAdmin() || isEmployee()) && <th>Action</th>}
          </tr>
        </thead>

        <tbody>

          {filteredEmployees.length > 0 ? (
            filteredEmployees.map((emp, index) => (
              <tr key={emp.id || index}>

                <td>{index + 1}</td>
                <td>{getEmployeeName(emp)}</td>
                <td>{emp?.dob || "--"}</td>
                <td>{emp?.department || "--"}</td>

                {/* ADMIN ACTIONS */}
                {isAdmin() && (
                  <td className="actions">

                    <button
                      className="view"
                      onClick={() =>
                        navigate(`${base}/employee-details/view/${emp.id}`)
                      }
                    >
                      View
                    </button>

                    <button
                      className="edit"
                      onClick={() =>
                        navigate(`${base}/employee-details/edit/${emp.id}`)
                      }
                    >
                      Edit
                    </button>

                    <button
                      className="salary"
                      onClick={() =>
                        navigate(`${base}/employee-details/salary/add/${emp.id}`)
                      }
                    >
                      Salary
                    </button>

                    <button className="delete">
                      Delete
                    </button>

                  </td>
                )}

                {/* EMPLOYEE ACTION */}
                {isEmployee() && (
                  <td>
                    <button
                      className="salary"
                      onClick={() =>
                        navigate(`${base}/employee-details/leave/apply/${emp.id}`)
                      }
                    >
                      Apply Leave
                    </button>
                  </td>
                )}

              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="5" className="no-data">
                No Employees Found
              </td>
            </tr>
          )}

        </tbody>
      </table>

    </div>
  );
}

export default EmployeeDetails;
